/*
 * Character Builder -> Roll20 importer
 *
 * Usage:
 *   !cb-import b64:<base64-payload>
 *   (legacy supported: !cb-import { ...payload json... })
 *
 * The payload shape expected by this script is generated by the app's
 * buildRoll20ModPayloadJson exporter (kind/version checked below).
 *
 * This script does NOT use ChatSetAttr. It directly reads/creates/updates
 * Roll20 Character + Attribute objects using the Roll20 API.
 */

(() => {
  "use strict";

  const SCRIPT_NAME = "CB Import";
  const COMMAND = "!cb-import";
  const PAYLOAD_KIND = "character-builder.roll20-mod-import";
  const PAYLOAD_VERSION = 1;

  const REPEATING_SECTIONS = ["skills", "attacks", "powers", "inventory"];
  const ABILITY_MOD_FIELDS = ["str_mod", "dex_mod", "con_mod", "int_mod", "wis_mod", "cha_mod"];
  const ABILITY_MOD_REFS = [
    "@{str_mod}",
    "@{dex_mod}",
    "@{con_mod}",
    "@{int_mod}",
    "@{wis_mod}",
    "@{cha_mod}",
  ];

  function whisper(msg) {
    sendChat(SCRIPT_NAME, "/w gm " + msg);
  }

  function info(msg) {
    whisper("[OK] " + msg);
  }

  function warn(msg) {
    whisper("[WARN] " + msg);
  }

  function fail(msg) {
    whisper("[ERROR] " + msg);
  }

  function safeString(value) {
    if (value === undefined || value === null) return "";
    return String(value);
  }

  function parsePayloadFromMessage(content) {
    const raw = content.slice(COMMAND.length).trim();
    if (!raw) {
      throw new Error("Missing payload. Send !cb-import followed by JSON or b64:<payload>.");
    }

    // Preferred command format to avoid Roll20 chat interpolation issues:
    // !cb-import b64:<base64-json>
    if (raw.indexOf("b64:") === 0) {
      const encoded = raw.slice(4).trim();
      if (!encoded) {
        throw new Error("Missing base64 payload after b64: prefix.");
      }

      try {
        const decoded = Buffer.from(encoded, "base64").toString("utf8");
        return JSON.parse(decoded);
      } catch (_error) {
        throw new Error("Invalid base64 payload.");
      }
    }

    // Typical case: raw is already JSON (starts with { ... }).
    if (raw[0] === "{" || raw[0] === "[") {
      return JSON.parse(raw);
    }

    // If users paste quoted JSON from another tool, strip matching wrappers.
    if (
      (raw[0] === '"' && raw[raw.length - 1] === '"') ||
      (raw[0] === "'" && raw[raw.length - 1] === "'")
    ) {
      const unwrapped = raw.slice(1, -1);
      return JSON.parse(unwrapped);
    }

    // Last attempt: still try JSON.parse in case it is valid but oddly prefixed.
    return JSON.parse(raw);
  }

  function validatePayload(payload) {
    if (!payload || typeof payload !== "object") {
      throw new Error("Payload is not an object.");
    }

    if (payload.kind !== PAYLOAD_KIND) {
      throw new Error(
        "Unsupported payload kind. Expected '" + PAYLOAD_KIND + "', got '" + safeString(payload.kind) + "'."
      );
    }

    if (payload.version !== PAYLOAD_VERSION) {
      throw new Error(
        "Unsupported payload version. Expected " + PAYLOAD_VERSION + ", got " + safeString(payload.version) + "."
      );
    }

    if (!payload.character || !safeString(payload.character.name).trim()) {
      throw new Error("Payload missing character.name.");
    }

    if (!payload.attributes || typeof payload.attributes !== "object") {
      throw new Error("Payload missing attributes object.");
    }

    if (!payload.repeating || typeof payload.repeating !== "object") {
      throw new Error("Payload missing repeating object.");
    }
  }

  function findCharacterByName(name) {
    const normalized = safeString(name).trim().toLowerCase();
    if (!normalized) return null;

    const all = findObjs({ _type: "character" }) || [];
    for (let i = 0; i < all.length; i++) {
      const candidateName = safeString(all[i].get("name")).trim().toLowerCase();
      if (candidateName === normalized) {
        return all[i];
      }
    }

    return null;
  }

  function getOrCreateCharacter(payloadCharacter) {
    const name = safeString(payloadCharacter.name).trim();
    let character = findCharacterByName(name);

    if (character) {
      return { character, created: false };
    }

    character = createObj("character", {
      name,
      inplayerjournals: "",
      controlledby: "",
    });

    return { character, created: true };
  }

  function findAttributesByName(characterId, attrName) {
    return (
      findObjs({
        _type: "attribute",
        characterid: characterId,
        name: attrName,
      }) || []
    );
  }

  function getCanonicalAttribute(characterId, attrName) {
    const found = findAttributesByName(characterId, attrName);
    if (found.length === 0) return null;

    // Keep the oldest by id for deterministic behavior, remove duplicates.
    found.sort((a, b) => {
      const idA = safeString(a.id);
      const idB = safeString(b.id);
      if (idA < idB) return -1;
      if (idA > idB) return 1;
      return 0;
    });

    const canonical = found[0];
    for (let i = 1; i < found.length; i++) {
      found[i].remove();
    }

    return canonical;
  }

  function upsertAttribute(characterId, attrName, currentValue, maxValue) {
    let attr = getCanonicalAttribute(characterId, attrName);
    if (!attr) {
      attr = createObj("attribute", {
        characterid: characterId,
        name: attrName,
        current: safeString(currentValue),
      });

      if (maxValue !== undefined) {
        attr.set("max", safeString(maxValue));
      }

      return { created: true, updated: false };
    }

    const next = { current: safeString(currentValue) };
    if (maxValue !== undefined) {
      next.max = safeString(maxValue);
    }

    attr.set(next);
    return { created: false, updated: true };
  }

  function upsertFlatAttributes(characterId, attributes) {
    let created = 0;
    let updated = 0;

    Object.keys(attributes).forEach((name) => {
      // Non-repeating attributes only. Repeating is handled in section replacement.
      if (name.indexOf("repeating_") === 0) return;

      const result = upsertAttribute(characterId, name, attributes[name]);
      if (result.created) created += 1;
      if (result.updated) updated += 1;
    });

    return { created, updated };
  }

  function upsertHp(characterId, hp) {
    if (!hp || typeof hp !== "object") {
      return { created: 0, updated: 0 };
    }

    let created = 0;
    let updated = 0;

    // Sheet-specific HP fields exported by the app.
    [
      ["hp_current", hp.current],
      ["hp_max", hp.max],
      ["hp_temp", hp.temp],
      ["hit_die", hp.hitDie],
      ["hit_dice_total", hp.hitDiceTotal],
    ].forEach((entry) => {
      const result = upsertAttribute(characterId, entry[0], entry[1]);
      if (result.created) created += 1;
      if (result.updated) updated += 1;
    });

    // Also upsert canonical Roll20-style hp attribute with current/max explicitly.
    const hpResult = upsertAttribute(characterId, "hp", hp.current, hp.max);
    if (hpResult.created) created += 1;
    if (hpResult.updated) updated += 1;

    return { created, updated };
  }

  function sectionPrefix(sectionName) {
    return "repeating_" + sectionName + "_";
  }

  function isSectionAttribute(attrName, sectionName) {
    return safeString(attrName).indexOf(sectionPrefix(sectionName)) === 0;
  }

  function clearRepeatingSection(characterId, sectionName) {
    const allAttrs =
      findObjs({
        _type: "attribute",
        characterid: characterId,
      }) || [];

    let removed = 0;
    for (let i = 0; i < allAttrs.length; i++) {
      const attr = allAttrs[i];
      const name = safeString(attr.get("name"));
      if (isSectionAttribute(name, sectionName)) {
        attr.remove();
        removed += 1;
      }
    }

    return removed;
  }

  function sanitizeRowId(rawRowId) {
    const rowId = safeString(rawRowId).trim();
    if (!rowId) {
      throw new Error("Repeating row missing rowId.");
    }

    // Guard against malformed row IDs generating bad attribute names.
    if (!/^[A-Za-z0-9_-]+$/.test(rowId)) {
      throw new Error("Invalid rowId '" + rowId + "'.");
    }

    return rowId;
  }

  function normalizeRowIdForRoll20(rawRowId) {
    const rowId = sanitizeRowId(rawRowId);
    // Roll20 sheet workers and getSectionIDs are most reliable with row IDs that
    // follow Roll20's generated pattern (leading '-'). Preserve payload stability
    // by applying a deterministic transform instead of generating a new random ID.
    return rowId.charAt(0) === "-" ? rowId : "-" + rowId;
  }

  function toInt(value) {
    return parseInt(safeString(value), 10) || 0;
  }

  function normalizeAbilityRef(value, baseAttrs) {
    const raw = safeString(value).trim().toLowerCase();
    if (!raw) return "@{str_mod}";

    if (ABILITY_MOD_REFS.indexOf(raw) >= 0) {
      return raw;
    }

    if (ABILITY_MOD_FIELDS.indexOf(raw) >= 0) {
      return "@{" + raw + "}";
    }

    // Backward compatibility for older payloads that exported numeric mod values.
    const parsed = parseInt(raw, 10);
    if (!Number.isNaN(parsed)) {
      const matches = ABILITY_MOD_FIELDS.filter((fieldName) => toInt(baseAttrs[fieldName]) === parsed);
      if (matches.length === 1) {
        return "@{" + matches[0] + "}";
      }
    }

    return "@{str_mod}";
  }

  function normalizePowerSaveAttr(value) {
    const raw = safeString(value).trim().toLowerCase();
    if (!raw || raw === "none") return "none";
    if (ABILITY_MOD_FIELDS.indexOf(raw) >= 0) return raw;

    const refMatch = raw.match(/^@\{(str_mod|dex_mod|con_mod|int_mod|wis_mod|cha_mod)\}$/);
    if (refMatch) {
      return refMatch[1];
    }

    return "none";
  }

  function computePowerDc(saveAttr, baseAttrs) {
    if (saveAttr === "none") return "";
    const pb = toInt(baseAttrs.pb);
    const mod = toInt(baseAttrs[saveAttr]);
    return String(8 + pb + mod);
  }

  function normalizeRepeatingRowAttributes(sectionName, fields, baseAttrs) {
    const normalized = {};
    Object.keys(fields || {}).forEach((key) => {
      normalized[key] = fields[key];
    });

    if (sectionName === "skills") {
      normalized.skillattr = normalizeAbilityRef(normalized.skillattr, baseAttrs);
      // Checkbox is rendered checked when current matches the input's value.
      normalized.skillprof = "@{pb}";
    }

    if (sectionName === "attacks") {
      normalized.attackattr = normalizeAbilityRef(normalized.attackattr, baseAttrs);
      // Per requirement: imported attacks are always proficient.
      normalized.attackprof = "@{pb}";
    }

    if (sectionName === "powers") {
      const saveAttr = normalizePowerSaveAttr(normalized.power_save_attr);
      normalized.power_save_attr = saveAttr;
      normalized.power_dc = computePowerDc(saveAttr, baseAttrs);
    }

    return normalized;
  }

  function writeRepeatingSection(characterId, sectionName, rows, baseAttrs) {
    const safeRows = Array.isArray(rows) ? rows : [];
    const seenRowIds = {};
    let attrsWritten = 0;

    safeRows.forEach((row, rowIndex) => {
      if (!row || typeof row !== "object") {
        throw new Error("Invalid row object in section '" + sectionName + "' at index " + rowIndex + ".");
      }

      const rowId = normalizeRowIdForRoll20(row.rowId);
      if (seenRowIds[rowId]) {
        throw new Error("Duplicate rowId '" + rowId + "' in section '" + sectionName + "'.");
      }
      seenRowIds[rowId] = true;

      const fields = row.attributes;
      if (!fields || typeof fields !== "object") {
        throw new Error("Missing row.attributes in section '" + sectionName + "' row '" + rowId + "'.");
      }

      const normalizedFields = normalizeRepeatingRowAttributes(sectionName, fields, baseAttrs);

      Object.keys(normalizedFields).forEach((fieldName) => {
        const fullName = "repeating_" + sectionName + "_" + rowId + "_" + fieldName;
        upsertAttribute(characterId, fullName, normalizedFields[fieldName]);
        attrsWritten += 1;
      });
    });

    return attrsWritten;
  }

  function replaceRepeatingSections(characterId, repeating, baseAttrs) {
    const summary = {};

    REPEATING_SECTIONS.forEach((sectionName) => {
      const removed = clearRepeatingSection(characterId, sectionName);
      const written = writeRepeatingSection(
        characterId,
        sectionName,
        repeating[sectionName],
        baseAttrs
      );
      summary[sectionName] = {
        removed,
        written,
        rows: Array.isArray(repeating[sectionName]) ? repeating[sectionName].length : 0,
      };
    });

    return summary;
  }

  function formatSectionSummary(repeatingSummary) {
    const chunks = [];
    REPEATING_SECTIONS.forEach((sectionName) => {
      const item = repeatingSummary[sectionName] || { removed: 0, written: 0, rows: 0 };
      chunks.push(
        sectionName +
          " rows=" +
          item.rows +
          " attrs_written=" +
          item.written +
          " attrs_removed=" +
          item.removed
      );
    });
    return chunks.join(" | ");
  }

  function runImport(payload) {
    validatePayload(payload);

    const characterResult = getOrCreateCharacter(payload.character);
    const character = characterResult.character;
    const characterId = character.id;

    // Keep sheet display name synchronized with payload character name.
    character.set("name", safeString(payload.character.name).trim());

    // Optional metadata fields useful for troubleshooting provenance.
    upsertAttribute(characterId, "cb_character_id", safeString(payload.character.id));
    upsertAttribute(characterId, "cb_campaign_id", safeString(payload.character.campaignId));
    upsertAttribute(characterId, "cb_class_id", safeString(payload.character.classId));
    upsertAttribute(characterId, "cb_race_id", safeString(payload.character.raceId));

    const flatResult = upsertFlatAttributes(characterId, payload.attributes);
    const hpResult = upsertHp(characterId, payload.hp);
    const repeatingSummary = replaceRepeatingSections(
      characterId,
      payload.repeating,
      payload.attributes || {}
    );

    info(
      "Import complete for '" +
        safeString(payload.character.name) +
        "' (" +
        characterId +
        ")" +
        (characterResult.created ? " [created new character]" : " [updated existing character]")
    );
    info(
      "Non-repeating attrs: created=" +
        flatResult.created +
        ", updated=" +
        flatResult.updated +
        " | HP attrs: created=" +
        hpResult.created +
        ", updated=" +
        hpResult.updated
    );
    info("Repeating replace summary: " + formatSectionSummary(repeatingSummary));
  }

  on("chat:message", (msg) => {
    try {
      if (!msg || msg.type !== "api" || typeof msg.content !== "string") return;
      if (msg.content.indexOf(COMMAND) !== 0) return;

      const payload = parsePayloadFromMessage(msg.content);
      runImport(payload);
    } catch (err) {
      const message = err && err.message ? err.message : safeString(err);
      fail("Import failed: " + message);
      warn("Tip: use the app's copied command (b64 format) to avoid Roll20 chat parsing issues.");
      log("[CB Import] Error: " + message);
    }
  });

  on("ready", () => {
    log("[CB Import] Ready. Command: " + COMMAND);
  });
})();
